#!/usr/bin/env bash
set -euo pipefail

HOST="localhost"
USER="backup_user"
PASS="BackupPass123"
MYSQL_BIN="mysql"
MYSQLDUMP_BIN="mysqldump"
BACKUP_DIR="/var/backups/mysql"
DATE="$(date +%F_%H-%M-%S)"
RETENTION_DAYS=7

mkdir -p "$BACKUP_DIR"

DATABASES="$($MYSQL_BIN -h "$HOST" -u "$USER" -p"$PASS" -Nse "SHOW DATABASES;" | grep -Ev '^(information_schema|performance_schema|mysql|sys)$')"

