  $MYSQLDUMP_BIN -h "$HOST" -u "$USER" -p"$PASS" --single-transaction --routines --triggers --events "$DB" | gzip > "$OUTFILE"
done

find "$BACKUP_DIR" -type f -name "*.sql.gz" -mtime +"$RETENTION_DAYS" -delete